            _minorState = MINOR_VALUE_EXPECTING_COMMA;
            return _currToken;
        }
    }
    if (ch != INT_COMMA) {
        if (ch == INT_RBRACKET) {
            return _closeArrayScope();
        }
        if (ch == INT_RCURLY){
            return _closeObjectScope();
        }
        if (ch == INT_SLASH) {
            return _startSlashComment(MINOR_VALUE_EXPECTING_COMMA);
        }
        if (ch == INT_HASH) {
            return _finishHashComment(MINOR_VALUE_EXPECTING_COMMA);
