    int ptr = _inputPtr;
    if (ptr >= _inputEnd) {
        _minorState = MINOR_VALUE_WS_AFTER_COMMA;
        return _updateTokenToNA();
    }
    ch = getByteFromBuffer(ptr);
    _inputPtr = ptr+1;
    if (ch <= 0x0020) {
        ch = _skipWS(ch);
