// Value MUST be preceded by a semi-colon (which may be surrounded by white-space)
protected final JsonToken _startValueExpectColon(int ch) throws JacksonException
{
    // First: any leading white space?
    if (ch <= 0x0020) {
        ch = _commentSkipper.skipWS(ch); // will skip through all available ws (and comments)
        if (ch <= 0) {
            _minorState = MINOR_VALUE_EXPECTING_COLON;
            return _currToken;
        }
    }
    if (ch != INT_COLON) {
        if (ch == INT_SLASH) {
            return _commentSkipper.startSlashComment(MINOR_VALUE_EXPECTING_COLON);
        }
        if (ch == INT_HASH) {
            return _commentSkipper.finishHashComment(MINOR_VALUE_EXPECTING_COLON);
        }
        // cannot omit colon here
        _reportUnexpectedChar(ch, "was expecting a colon to separate field name and value");
    }
    int ptr = _inputPtr;
    if (ptr >= _inputEnd) {
        _minorState = MINOR_VALUE_LEADING_WS;
        return _updateTokenToNA();
    }
    ch = getByteFromBuffer(ptr);
    _inputPtr = ptr+1;
    if (ch <= 0x0020) {
        ch = _commentSkipper.skipWS(ch); // will skip through all available ws (and comments)
        if (ch <= 0) {
            _minorState = MINOR_VALUE_LEADING_WS;
            return _currToken;
        }
    }
    _updateTokenLocation();
    if (ch == INT_QUOTE) {
        return _startString();
    }
    switch (ch) {
    case '#':
        return _commentSkipper.finishHashComment(MINOR_VALUE_LEADING_WS);
    case '+':
        return _startPositiveNumber();
    case '-':
        return _startNegativeNumber();
    case '/':
        return _commentSkipper.startSlashComment(MINOR_VALUE_LEADING_WS);

    // Should we have separate handling for plus? Although
    // it is not allowed per se, it may be erroneously used,
    // and could be indicate by a more specific error message.
    case '0':
        return _startNumberLeadingZero();

    case '1':
    case '2': case '3':
    case '4': case '5':
    case '6': case '7':
    case '8': case '9':
        return _startPositiveNumber(ch);
    case 'f':
        return _startFalseToken();
    case 'n':
        return _startNullToken();
    case 't':
        return _startTrueToken();
    case '[':
        return _startArrayScope();
    case '{':
        return _startObjectScope();
    default:
    }
    return _startUnexpectedValue(false, ch);
}

// Method called when we have already gotten a comma (i.e. not the first value)
protected final JsonToken _startValueAfterComma(int ch) throws JacksonException
{
    // First: any leading white space?
    if (ch <= 0x0020) {
        ch = _commentSkipper.skipWS(ch);
        if (ch <= 0) {
            _minorState = MINOR_VALUE_WS_AFTER_COMMA;
            return _currToken;
        }
    }
    _updateTokenLocation();
    if (ch == INT_QUOTE) {
        return _startString();
    }
    switch (ch) {
    case '#':
        return _commentSkipper.finishHashComment(MINOR_VALUE_WS_AFTER_COMMA);
    case '+':
        return _startPositiveNumber();
    case '-':
        return _startNegativeNumber();
    case '/':
        return _commentSkipper.startSlashComment(MINOR_VALUE_WS_AFTER_COMMA);

    // Should we have separate handling for plus? Although
    // it is not allowed per se, it may be erroneously used,
    // and could be indicate by a more specific error message.
    case '0':
        return _startNumberLeadingZero();
    case '1':
    case '2':
    case '3':
    case '4':
    case '5':
    case '6':
    case '7':
    case '8':
    case '9':
        return _startPositiveNumber(ch);
    case 'f':
        return _startFalseToken();
    case 'n':
        return _startNullToken();
    case 't':
        return _startTrueToken();
    case '[':
        return _startArrayScope();
    case INT_RBRACKET:
        // Was that a trailing comma?
        if ((_formatReadFeatures & FEAT_MASK_TRAILING_COMMA) != 0) {
            return _closeArrayScope();
        }
        break;
    case '{':
        return _startObjectScope();
    case INT_RCURLY:
        // Was that a trailing comma?
        if ((_formatReadFeatures & FEAT_MASK_TRAILING_COMMA) != 0) {
            return _closeObjectScope();
        }
        break;
    default:
    }
    return _startUnexpectedValue(true, ch);
}

protected final JsonToken _startUnexpectedValue(boolean leadingComma, int ch) throws JacksonException
{
    switch (ch) {
    case INT_RBRACKET:
        if (!_streamReadContext.inArray()) {
            break;
        }
        // fall through
    case ',':
        // 28-Mar-2016: [core#116]: If Feature.ALLOW_MISSING_VALUES is enabled
        //   we may allow "missing values", that is, encountering a trailing
        //   comma or closing marker where value would be expected
        // 11-May-2020, tatu: [core#616] No commas in root level
        if (!_streamReadContext.inRoot()) {
            if ((_formatReadFeatures & FEAT_MASK_ALLOW_MISSING) != 0) {
                --_inputPtr;
                return _valueComplete(JsonToken.VALUE_NULL);
            }
        }
        // fall through
    case INT_RCURLY:
        // Error: neither is valid at this point; valid closers have
        // been handled earlier
        break;
    case '\'':
        if ((_formatReadFeatures & FEAT_MASK_ALLOW_SINGLE_QUOTES) != 0) {
            return _startAposString();
        }
        break;
    case '+':
        return _finishNonStdToken(NON_STD_TOKEN_PLUS_INFINITY, 1);
    case 'N':
        return _finishNonStdToken(NON_STD_TOKEN_NAN, 1);
    case 'I':
        return _finishNonStdToken(NON_STD_TOKEN_INFINITY, 1);
    }
    // !!! TODO: maybe try to collect more information for better diagnostics
    _reportUnexpectedChar(ch, "expected a valid value "+_validJsonValueList());
    return null;
}

