    private final static int INT_QUOTE = 0x0022; // '"'
    private final static int INT_BACKSLASH = 0x005C; // '\'

    public UTF8DataInputBase64Decoder(DataInput inputData, IOContext ioContext, JsonParserBase parser) {
        _inputData = inputData;
        _ioContext = ioContext;
        _parser = parser;
    }

    /**
     * Decodes a full Base64 value from the input stream into a byte array.
     * This corresponds to the original `_decodeBase64(Base64Variant)` method.
     */
    public byte[] decode(Base64Variant b64variant) throws IOException {
        ByteArrayBuilder builder = _parser._getByteArrayBuilder();
        byte[] buffer = _ioContext.allocBase64Buffer();
        try {
            readBinary(b64variant, builder, buffer);
        } finally {
            _ioContext.releaseBase64Buffer(buffer);
        }
        return builder.toByteArray();
    }

    /**
     * Reads and decodes Base64 content from the input stream, writing it to the
     * provided OutputStream. This corresponds to the original `_readBinary` method.
     */
    public int readBinary(Base64Variant b64variant, OutputStream out, byte[] buffer) throws IOException {
        int outputPtr = 0;
        final int outputEnd = buffer.length - 3;
        int outputCount = 0;

        while (true) {
            // first, we'll skip preceding white space, if any
            int ch;
            do {
                ch = _inputData.readUnsignedByte();
            } while (ch <= INT_SPACE);
            int bits = b64variant.decodeBase64Char(ch);
            if (bits < 0) { // reached the end, fair and square?
                if (ch == INT_QUOTE) {
                    break;
                }
                bits = _decodeBase64Escape(b64variant, ch, 0);
                if (bits < 0) { // white space to skip
                    continue;
                }
            }

            // enough room? If not, flush
            if (outputPtr > outputEnd) {
                outputCount += outputPtr;
                out.write(buffer, 0, outputPtr);
                outputPtr = 0;
            }

            int decodedData = bits;

            // then second base64 char; can't get padding yet, nor ws
            ch = _inputData.readUnsignedByte();
            bits = b64variant.decodeBase64Char(ch);
            if (bits < 0) {
                bits = _decodeBase64Escape(b64variant, ch, 1);
            }
            decodedData = (decodedData << 6) | bits;

            // third base64 char; can be padding, but not ws
            ch = _inputData.readUnsignedByte();
            bits = b64variant.decodeBase64Char(ch);

            // First branch: can get padding (-> 1 byte)
            if (bits < 0) {
                if (bits != Base64Variant.BASE64_VALUE_PADDING) {
                    // could also just be 'missing'  padding
                    if (ch == INT_QUOTE) {
                        decodedData >>= 4;
                        buffer[outputPtr++] = (byte) decodedData;
                        if (b64variant.requiresPaddingOnRead()) {
                            _handleBase64MissingPadding(b64variant);
                        }
                        break;
                    }
                    bits = _decodeBase64Escape(b64variant, ch, 2);
                }
                if (bits == Base64Variant.BASE64_VALUE_PADDING) {
                    // Ok, must get padding
                    ch = _inputData.readUnsignedByte();
                    if (!b64variant.usesPaddingChar(ch)) {
                        if ((ch != INT_BACKSLASH)
